<!doctype html><html><head><meta charset="utf-8"><style>body{font-family:DejaVu Sans;font-size:9px;color:#0f172a}h1{color:#0369a1}table{width:100%;border-collapse:collapse}th{background:#0369a1;color:#fff;padding:7px}td{padding:6px;border-bottom:1px solid #ddd}.num{text-align:right}</style></head><body><h1>Laporan Penjualan</h1><p>Dicetak {{ now()->format('d/m/Y H:i') }}</p><table><thead><tr><th>Invoice</th><th>Tanggal</th><th>Pelanggan</th><th>Subtotal</th><th>Diskon</th><th>Pajak</th><th>Grand Total</th><th>Terbayar</th><th>Sisa</th><th>Status</th></tr></thead><tbody>@foreach($rows as $row)<tr><td>{{ $row->invoice_number }}</td><td>{{ $row->invoice_date->format('d/m/Y') }}</td><td>{{ $row->billing_company ?: $row->billing_name }}</td><td class="num">{{ number_format((float)$row->subtotal,0,',','.') }}</td><td class="num">{{ number_format((float)$row->discount_amount,0,',','.') }}</td><td class="num">{{ number_format((float)$row->tax_amount,0,',','.') }}</td><td class="num">{{ number_format((float)$row->grand_total,0,',','.') }}</td><td class="num">{{ number_format((float)$row->paid_amount,0,',','.') }}</td><td class="num">{{ number_format((float)$row->remaining_amount,0,',','.') }}</td><td>{{ $row->status->value }}</td></tr>@endforeach</tbody></table></body></html>
